#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int a, b; scanf("%d %d", &a, &b);
        int sum = a + b;
        if (sum < 3) printf("1\n");
        else if (sum <= 10) printf("2\n");
        else if (sum <= 60) printf("3\n");
        else printf("4\n");
    }
    return 0;
}

